<?php
namespace App\Domain\Admin\Content;
use App\Domain\Equipment\EquipmentType;
use App\Domain\Equipment\EquipmentRequirementValidator;use App\Domain\Equipment\EquippableItemValidator;use App\Domain\Loot\LootConfigurationValidator;use App\Domain\Media\CatalogImages\CatalogImageService;use App\Domain\Media\CatalogImages\CatalogImageType;use App\Domain\WorldCatalog\CatalogStatus;use App\Domain\WorldCatalog\WorldCatalogValidator;use App\Models\CharacterClass;use App\Models\Item;use App\Models\Monster;use App\Models\MonsterLootEntry;use App\Models\Zone;use App\Models\ZoneMonster;use Illuminate\Http\UploadedFile;use Illuminate\Support\Facades\DB;use InvalidArgumentException;
final class ContentAdminService{private $catalog;private $items;private $loot;private $requirements;private $images;public function __construct(WorldCatalogValidator $catalog,EquippableItemValidator $items,LootConfigurationValidator $loot,EquipmentRequirementValidator $requirements,CatalogImageService $images){$this->catalog=$catalog;$this->items=$items;$this->loot=$loot;$this->requirements=$requirements;$this->images=$images;}
public function saveItem(array $data,Item $item=null){$image=isset($data['image'])&&$data['image'] instanceof UploadedFile?$data['image']:null;unset($data['image']);$model=DB::transaction(function()use($data,$item){$ids=array_values(array_unique(array_map('intval',isset($data['character_class_ids'])?$data['character_class_ids']:[])));unset($data['character_class_ids']);$model=$item&&$item->exists?Item::whereKey($item->id)->lockForUpdate()->firstOrFail():new Item();$historical=$model->exists?$model->allowedCharacterClasses()->orderBy('character_classes.id')->get():collect();$selected=empty($ids)?collect():CharacterClass::whereIn('id',$ids)->orderBy('id')->lockForUpdate()->get();if($selected->count()!==count($ids))throw new InvalidArgumentException('Invalid character class selection.');$data['code']=$this->catalog->normalizeCode($data['code']);if((isset($data['equipment_type'])?$data['equipment_type']:null)!==EquipmentType::WEAPON){$data['hand_requirement']=null;$data['equipment_family']=null;}$candidate=new Item($data);$this->catalog->assertItemType($candidate->item_type);$this->catalog->assertItemRarity($candidate->rarity);$this->catalog->assertStatus($candidate->status);$this->catalog->assertItemStack((bool)$candidate->is_stackable,$candidate->max_stack);$this->items->equipmentType($candidate);if(!$model->exists&&$candidate->equipment_type===EquipmentType::WEAPON&&($candidate->hand_requirement===null||$candidate->equipment_family===null))throw new InvalidArgumentException('Los nuevos objetos de mano requieren requisito y familia.');$this->requirements->validateSelection($selected,$historical);$this->requirements->validate($candidate,$selected);$model->fill($data);$model->save();$model->allowedCharacterClasses()->sync($ids);return$model;});if($image)$this->images->replace($model,CatalogImageType::ITEM,$image);return$model;}
public function deactivateItem(Item $item){$item->update(['status'=>CatalogStatus::INACTIVE]);}public function deleteItemImage(Item $item){$this->images->delete($item,CatalogImageType::ITEM);}
public function saveMonster(array $data,Monster $monster=null){$image=isset($data['image'])&&$data['image'] instanceof UploadedFile?$data['image']:null;unset($data['image']);$model=DB::transaction(function()use($data,$monster){$this->catalog->assertStatus($data['status']);$data['code']=$this->catalog->normalizeCode($data['code']);if((int)$data['gold_min']>(int)$data['gold_max'])throw new InvalidArgumentException('Gold minimum cannot exceed maximum.');$model=$monster?:new Monster();$model->fill($data);$model->save();return$model;});if($image)$this->images->replace($model,CatalogImageType::MONSTER,$image);return$model;}public function deleteMonsterImage(Monster $monster){$this->images->delete($monster,CatalogImageType::MONSTER);}public function deactivateMonster(Monster $monster){$monster->update(['status'=>CatalogStatus::INACTIVE]);}
public function saveZone(array $data,Zone $zone=null){return DB::transaction(function()use($data,$zone){$this->catalog->assertStatus($data['status']);$this->catalog->assertZoneType($data['zone_type']);$this->catalog->assertLevelRange($data['recommended_level_min'],$data['recommended_level_max']);$data['code']=$this->catalog->normalizeCode($data['code']);$model=$zone?:new Zone();$model->fill($data);$model->save();return$model;});}public function deactivateZone(Zone $zone){$zone->update(['status'=>CatalogStatus::INACTIVE]);}public function saveZoneMonster(Zone $zone,Monster $monster,array $data){return DB::transaction(function()use($zone,$monster,$data){$this->catalog->assertZoneMonster($data['weight'],$data['minimum_character_level'],$data['maximum_character_level']);$this->catalog->assertStatus($data['status']);$row=ZoneMonster::where('zone_id',$zone->id)->where('monster_id',$monster->id)->first();if(!$row)$row=new ZoneMonster(['zone_id'=>$zone->id,'monster_id'=>$monster->id]);$row->fill($data);$row->save();return$row;});}public function removeZoneMonster(Zone $zone,Monster $monster){ZoneMonster::where('zone_id',$zone->id)->where('monster_id',$monster->id)->delete();}
public function saveLoot(Monster $monster,Item $item,array $data,MonsterLootEntry $entry=null){return DB::transaction(function()use($monster,$item,$data,$entry){$this->loot->validate($monster,$item,(int)$data['drop_chance_basis_points'],(int)$data['minimum_quantity'],(int)$data['maximum_quantity'],$data['status'],$entry);$model=$entry?:new MonsterLootEntry(['monster_id'=>$monster->id]);$model->fill($data);$model->item_id=$item->id;$model->save();return$model;});}public function deactivateLoot(Monster $monster,MonsterLootEntry $entry){return DB::transaction(function()use($monster,$entry){if((int)$entry->monster_id!==(int)$monster->id)throw new InvalidArgumentException('Existing entry mismatch.');$entry->status=CatalogStatus::INACTIVE;$entry->save();return$entry;});}public function activateLoot(Monster $monster,MonsterLootEntry $entry){return DB::transaction(function()use($monster,$entry){$item=Item::findOrFail($entry->item_id);$this->loot->validate($monster,$item,(int)$entry->drop_chance_basis_points,(int)$entry->minimum_quantity,(int)$entry->maximum_quantity,CatalogStatus::ACTIVE,$entry);$entry->status=CatalogStatus::ACTIVE;$entry->save();return$entry;});}}
